# Vencord Auto-Updater - desktop app (WPF GUI + system tray + background monitor)
# Detects Discord/PTB/custom installs that are running without Vencord and
# re-injects Vencord + restarts Discord. Configurable via the UI; runs in tray.

[CmdletBinding()]
param(
    [switch]$Tray,      # start minimized to the system tray (used by autostart)
    [switch]$SelfTest   # build UI then exit (used to validate without showing a window)
)

$ErrorActionPreference = 'Stop'
# Resolve our own folder whether we run as a .ps1 or as a compiled .exe (ps2exe).
$ScriptDir = if ($PSScriptRoot) { $PSScriptRoot }
elseif ($MyInvocation.MyCommand.Path) { Split-Path -Parent $MyInvocation.MyCommand.Path }
else { Split-Path -Parent ([System.Diagnostics.Process]::GetCurrentProcess().MainModule.FileName) }
$LogFile    = Join-Path $ScriptDir 'vencord-auto-updater.log'
$ConfigFile = Join-Path $ScriptDir 'config.json'

# ---------------------------------------------------------------- assemblies
Add-Type -AssemblyName PresentationFramework, PresentationCore, WindowsBase,
                       System.Windows.Forms, System.Drawing, System.Xaml | Out-Null

# Hide the console window if we were launched with one.
try {
    $native = Add-Type -PassThru -Name VAUNative -Namespace VAU -MemberDefinition @'
[System.Runtime.InteropServices.DllImport("kernel32.dll")] public static extern System.IntPtr GetConsoleWindow();
[System.Runtime.InteropServices.DllImport("user32.dll")] public static extern bool ShowWindow(System.IntPtr h, int n);
'@
    $hwnd = $native::GetConsoleWindow(); if ($hwnd -ne [IntPtr]::Zero) { [void]$native::ShowWindow($hwnd, 0) }
} catch { }

# ------------------------------------------------------------------ branding
$AppName  = 'Vencord Auto-Updater'
$Branches = @('Discord', 'DiscordPTB', 'DiscordCanary', 'DiscordDevelopment')
$VencordBase = if ($env:VENCORD_USER_DATA_DIR) { $env:VENCORD_USER_DATA_DIR } else { Join-Path $env:APPDATA 'Vencord' }
$PatcherPath = Join-Path (Join-Path $VencordBase 'dist') 'patcher.js'

# Tray state icons, embedded as base64 .ico: green = monitoring ON, red = OFF.
$IconOnB64  = ''
$IconOffB64 = ''

function ConvertTo-IconFromB64([string]$b64) {
    if (-not $b64 -or $b64.StartsWith('@@')) { return $null }
    try {
        $bytes = [Convert]::FromBase64String($b64)
        $ms = New-Object System.IO.MemoryStream(, $bytes)
        return New-Object System.Drawing.Icon($ms)
    } catch { return $null }
}

# script-scope state
$script:Config     = $null
$script:LastStates = @{}
$script:Alerted    = @{}
$script:CurrentAlert = $null
$script:Win = $null; $script:Ni = $null; $script:App = $null; $script:Timer = $null
$script:IconOn = $null; $script:IconOff = $null

# ------------------------------------------------------------------ helpers
function Write-Log {
    param([string]$Message, [string]$Level = 'INFO')
    $line = "{0} [{1}] {2}" -f (Get-Date -Format 'yyyy-MM-dd HH:mm:ss'), $Level, $Message
    try {
        if ((Test-Path $LogFile) -and ((Get-Item $LogFile).Length -gt 1MB)) { Move-Item $LogFile "$LogFile.old" -Force }
        Add-Content -Path $LogFile -Value $line -Encoding UTF8
    } catch { }
}

function Brush([string]$hex) {
    [System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString($hex))
}

function Darken([string]$hex, [double]$f = 0.82) {
    $c = [System.Windows.Media.ColorConverter]::ConvertFromString($hex)
    '#{0:X2}{1:X2}{2:X2}' -f [byte][math]::Round($c.R * $f), [byte][math]::Round($c.G * $f), [byte][math]::Round($c.B * $f)
}

function New-Glow([string]$hex, [double]$blur = 14) {
    $e = New-Object System.Windows.Media.Effects.DropShadowEffect
    $e.BlurRadius = $blur; $e.ShadowDepth = 0; $e.Opacity = 0.9
    $e.Color = [System.Windows.Media.ColorConverter]::ConvertFromString($hex)
    $e
}

function New-Gradient([string]$from, [string]$to, [bool]$horizontal = $false) {
    $b = New-Object System.Windows.Media.LinearGradientBrush
    if ($horizontal) { $b.StartPoint = '0,0'; $b.EndPoint = '1,0' } else { $b.StartPoint = '0,0'; $b.EndPoint = '0,1' }
    $b.GradientStops.Add((New-Object System.Windows.Media.GradientStop([System.Windows.Media.ColorConverter]::ConvertFromString($from), 0)))
    $b.GradientStops.Add((New-Object System.Windows.Media.GradientStop([System.Windows.Media.ColorConverter]::ConvertFromString($to), 1)))
    $b
}

# Theme palettes. "Discord" is the default signature dark-blurple look.
$Themes = [ordered]@{
    Discord      = @{ Label = 'Discord';       Bg = '#1E1F22'; Card = '#2B2D31'; Card2 = '#313338'; Border = '#3A3C42'; Text = '#F2F3F5'; Sub = '#B5BAC1'; Accent = '#5865F2'; AccentHover = '#4752C4'; OnAccent = '#FFFFFF'; Ghost = '#383A40'; GhostHover = '#41434A'; RowBg = '#313338'; On = '#23A55A'; OnText = '#FFFFFF'; Scroll = '#4E5058' }
    Dark         = @{ Label = 'Dark';          Bg = '#0C0C0E'; Card = '#161719'; Card2 = '#1D1E21'; Border = '#2A2B2F'; Text = '#ECECEC'; Sub = '#9A9CA1'; Accent = '#A8ADB5'; AccentHover = '#878C94'; OnAccent = '#0C0C0E'; Ghost = '#1D1E21'; GhostHover = '#26272B'; RowBg = '#161719'; On = '#23A55A'; OnText = '#FFFFFF'; Scroll = '#3A3B40' }
    Light        = @{ Label = 'Light';         Bg = '#E1E3E7'; Card = '#FFFFFF'; Card2 = '#F4F5F7'; Border = '#D2D5DA'; Text = '#1A1B1E'; Sub = '#5C5E66'; Accent = '#5865F2'; AccentHover = '#4752C4'; OnAccent = '#FFFFFF'; Ghost = '#E6E8EC'; GhostHover = '#D8DBE0'; RowBg = '#F2F3F5'; On = '#1F9D55'; OnText = '#FFFFFF'; Scroll = '#C2C6CC' }
    HighContrast = @{ Label = 'High Contrast'; Bg = '#000000'; Card = '#000000'; Card2 = '#000000'; Border = '#BB86FC'; Text = '#FFFFFF'; Sub = '#E6D6FF'; Accent = '#C77DFF'; AccentHover = '#A855F7'; OnAccent = '#000000'; Ghost = '#000000'; GhostHover = '#2A1F3D'; RowBg = '#000000'; On = '#33B5FF'; OnText = '#000000'; Scroll = '#BB86FC' }
}

function Get-ThemePalette {
    $t = "$($script:Config.ui.theme)"
    if (-not $Themes.Contains($t)) { $t = 'Discord' }
    $Themes[$t]
}

function Apply-Theme {
    if (-not $script:Win) { return }
    $p = Get-ThemePalette
    $map = [ordered]@{ Bg = 'Bg'; Card = 'Card'; Card2 = 'Card2'; Border = 'Border'; Text = 'Text'; Sub = 'Sub'; Accent = 'Accent'; AccentHover = 'AccentHover'; OnAccent = 'OnAccent'; GhostBg = 'Ghost'; GhostHover = 'GhostHover'; Scroll = 'Scroll' }
    foreach ($rk in $map.Keys) { $script:Win.Resources[$rk] = Brush $p[$map[$rk]] }
    $td = $script:Win.FindName('TitleDot'); if ($td) { $td.Effect = New-Glow $p.Accent 12 }
    $strip = $script:Win.FindName('AccentStrip'); if ($strip) { $strip.Background = New-Gradient $p.Accent $p.AccentHover $false }
    $ul = $script:Win.FindName('TitleUnderline'); if ($ul) { $ul.Background = New-Gradient $p.Accent $p.Bg $true }
    Update-StatusUi; Update-SettingsUi; Build-InstallRows
}

function ConvertFrom-Xaml([string]$xaml) {
    $sr = New-Object System.IO.StringReader $xaml
    $xr = [System.Xml.XmlReader]::Create($sr)
    [System.Windows.Markup.XamlReader]::Load($xr)
}

# ---- patch engine (port of the Vencord Installer patch) -------------------
function Get-StubAsarBytes {
    param([Parameter(Mandatory)][string]$Patcher)
    $enc = [System.Text.Encoding]::UTF8
    $patcherJson = $Patcher | ConvertTo-Json
    $indexJs     = "require($patcherJson)"
    $packageJson = "{`n`t`"name`": `"discord`",`n`t`"main`": `"index.js`"`n}"
    $indexLen = $enc.GetByteCount($indexJs); $pkgLen = $enc.GetByteCount($packageJson)
    $fileContents = $indexJs + $packageJson
    $header = '{"files":{"index.js":{"size":' + $indexLen + ',"offset":"0"},' +
              '"package.json":{"size":' + $pkgLen + ',"offset":"' + $indexLen + '"}}}'
    $headerStringSize = $enc.GetByteCount($header)
    $dataSize = 4
    $alignedSize = ($headerStringSize + $dataSize - 1) -band (-bnot ($dataSize - 1))
    $headerSize = $alignedSize + 8; $headerObjectSize = $alignedSize + $dataSize
    $diff = $alignedSize - $headerStringSize
    if ($diff -gt 0) { $header += ('0' * $diff) }
    $ms = New-Object System.IO.MemoryStream; $bw = New-Object System.IO.BinaryWriter($ms)
    try {
        foreach ($n in @($dataSize, $headerSize, $headerObjectSize, $headerStringSize)) { $bw.Write([int32]$n) }
        $bw.Write($enc.GetBytes($header)); $bw.Write($enc.GetBytes($fileContents)); $bw.Flush()
        return $ms.ToArray()
    } finally { $bw.Dispose(); $ms.Dispose() }
}
$script:Stub = $null

function Get-LatestAppDir {
    param([string]$BranchRoot)
    if (-not (Test-Path $BranchRoot)) { return $null }
    Get-ChildItem -Path $BranchRoot -Directory -Filter 'app-*' -ErrorAction SilentlyContinue |
        Where-Object { Test-Path (Join-Path $_.FullName 'resources') } |
        Sort-Object @{ Expression = { try { [version]$_.Name.Substring(4) } catch { [version]'0.0.0' } } } |
        Select-Object -Last 1
}

function Get-BranchFromLeaf([string]$path) {
    $leaf = (Split-Path -Leaf $path).ToLower()
    if ($leaf -match 'canary') { 'DiscordCanary' }
    elseif ($leaf -match 'ptb') { 'DiscordPTB' }
    elseif ($leaf -match 'development|dev') { 'DiscordDevelopment' }
    else { 'Discord' }
}

function Get-State($inst) {
    $running = [bool](Get-Process -Name $inst.branch -ErrorAction SilentlyContinue)
    $appDir = Get-LatestAppDir $inst.path
    $patched = $false; $appName = $null; $resources = $null
    if ($appDir) {
        $appName = $appDir.Name
        $resources = Join-Path $appDir.FullName 'resources'
        $patched = Test-Path (Join-Path $resources '_app.asar')
    }
    [pscustomobject]@{ Running = $running; Patched = $patched; AppName = $appName; Resources = $resources; Installed = [bool]$appDir }
}

function Stop-DiscordProcesses([string]$ProcessName) {
    $procs = Get-Process -Name $ProcessName -ErrorAction SilentlyContinue
    if (-not $procs) { return }
    Write-Log "Stopping $($procs.Count) '$ProcessName' process(es) to patch."
    $procs | Stop-Process -Force -ErrorAction SilentlyContinue
    for ($i = 0; $i -lt 50; $i++) { Start-Sleep -Milliseconds 200; if (-not (Get-Process -Name $ProcessName -ErrorAction SilentlyContinue)) { break } }
    Start-Sleep -Milliseconds 300
}

function Invoke-Patch([string]$ResourcesDir, [byte[]]$StubBytes) {
    $appAsar = Join-Path $ResourcesDir 'app.asar'; $bakAsar = Join-Path $ResourcesDir '_app.asar'
    if (-not (Test-Path $appAsar)) { throw "app.asar missing in $ResourcesDir" }
    if (Test-Path $bakAsar) { throw "_app.asar already present in $ResourcesDir" }
    Rename-Item -LiteralPath $appAsar -NewName '_app.asar' -ErrorAction Stop
    try { [System.IO.File]::WriteAllBytes($appAsar, $StubBytes) }
    catch { if (-not (Test-Path $appAsar)) { Rename-Item -LiteralPath $bakAsar -NewName 'app.asar' -ErrorAction SilentlyContinue }; throw }
}

function Start-Discord([string]$BranchRoot, [string]$ExeName) {
    $update = Join-Path $BranchRoot 'Update.exe'
    if (Test-Path $update) { Start-Process -FilePath $update -ArgumentList @('--processStart', $ExeName) | Out-Null }
}

# ------------------------------------------------------------------ config
function Find-StandardInstalls {
    $found = @()
    foreach ($b in $Branches) {
        $root = Join-Path $env:LOCALAPPDATA $b
        if (Test-Path (Join-Path $root 'Update.exe')) {
            $found += [pscustomobject]@{ name = $b; branch = $b; path = $root; custom = $false }
        }
    }
    $found
}

function New-Install($name, $branch, $path, $enabled, $custom) {
    [pscustomobject]@{ name = $name; branch = $branch; path = $path; enabled = [bool]$enabled; custom = [bool]$custom }
}

function Add-IfMissing($obj, $name, $value) {
    if ($null -eq $obj.PSObject.Properties[$name]) { $obj | Add-Member -NotePropertyName $name -NotePropertyValue $value -Force }
}

function Ensure-ConfigDefaults {
    $c = $script:Config
    Add-IfMissing $c 'monitoringEnabled' $true
    Add-IfMissing $c 'intervalSeconds' 20
    Add-IfMissing $c 'installs' @()
    $c.installs = @($c.installs)
    Add-IfMissing $c 'ui'   ([pscustomobject]@{})
    Add-IfMissing $c.ui 'theme' 'Discord'
    Add-IfMissing $c.ui 'notificationsEnabled' $true
    Add-IfMissing $c.ui 'notifyDurationSec' 7
    Add-IfMissing $c.ui 'notifyStyle' 'bar'
    Add-IfMissing $c.ui 'notifyScale' 1.0
}

function Load-Config {
    $loaded = $false
    if (Test-Path $ConfigFile) {
        try { $script:Config = Get-Content $ConfigFile -Raw | ConvertFrom-Json; $loaded = $true }
        catch { Write-Log "Bad config, recreating: $($_.Exception.Message)" 'WARN' }
    }
    if (-not $loaded) {
        # first run: auto-detect. Discord enabled by default; others disabled.
        $installs = @()
        foreach ($d in Find-StandardInstalls) { $installs += New-Install $d.name $d.branch $d.path ($d.branch -eq 'Discord') $false }
        $script:Config = [pscustomobject]@{ monitoringEnabled = $true; intervalSeconds = 20; installs = $installs }
    }
    Ensure-ConfigDefaults
    Save-Config
}

function Save-Config {
    try { $script:Config | ConvertTo-Json -Depth 6 | Set-Content -Path $ConfigFile -Encoding UTF8 } catch { Write-Log "Save config failed: $($_.Exception.Message)" 'ERROR' }
}

function Ensure-Install($name, $branch, $path, $enabled, $custom) {
    $existing = $script:Config.installs | Where-Object { $_.path -eq $path }
    if ($existing) { $existing.enabled = $enabled; return $false }
    $script:Config.installs = @($script:Config.installs) + (New-Install $name $branch $path $enabled $custom)
    return $true
}

# ------------------------------------------------------------------ alert (top-left banner)
$NotifyStyles = @('bar', 'solid', 'minimal', 'outline')

function New-TB([string]$text, [string]$color, [double]$size, [bool]$bold) {
    $t = New-Object System.Windows.Controls.TextBlock
    $t.Text = $text; $t.Foreground = Brush $color; $t.FontSize = $size; $t.TextWrapping = 'Wrap'
    if ($bold) { $t.FontWeight = 'Bold' }
    $t
}

# Build the banner visual from the current theme + style + scale (no per-alert colours).
function New-AlertVisual([string]$message) {
    $ui = $script:Config.ui
    $p = Get-ThemePalette
    $scale = [double]$ui.notifyScale; if ($scale -le 0) { $scale = 1 }
    $style = "$($ui.notifyStyle)"; if ($NotifyStyles -notcontains $style) { $style = 'bar' }
    $isHC = "$($ui.theme)" -eq 'HighContrast'
    $pad = [int][math]::Round(16 * $scale)
    $titleSize = [math]::Round(13 * $scale, 1)
    $msgSize = [math]::Round(12.5 * $scale, 1)
    $accent = $p.Accent; $bg = $p.Card; $text = $p.Text; $sub = $p.Sub; $border = $p.Border; $onAccent = $p.OnAccent

    $outer = New-Object System.Windows.Controls.Border
    $outer.CornerRadius = [System.Windows.CornerRadius]::new([math]::Round(12 * $scale))
    $outer.Padding = [System.Windows.Thickness]::new($pad)
    $eff = New-Object System.Windows.Media.Effects.DropShadowEffect
    $eff.BlurRadius = 22; $eff.ShadowDepth = 0; $eff.Opacity = 0.7
    $outer.Effect = $eff
    $outer.BorderBrush = Brush $border
    $outer.BorderThickness = [System.Windows.Thickness]::new($(if ($isHC) { [math]::Max(3, [int][math]::Round(3 * $scale)) } else { 1 }))

    switch ($style) {
        'solid' {
            $outer.Background = Brush $accent
            $sp = New-Object System.Windows.Controls.StackPanel
            $sp.Children.Add((New-TB 'Vencord Auto-Updater' $onAccent $titleSize $true)) | Out-Null
            $m = New-TB $message $onAccent $msgSize $false; $m.Margin = [System.Windows.Thickness]::new(0, [int](5 * $scale), 0, 0)
            $sp.Children.Add($m) | Out-Null
            $outer.Child = $sp
        }
        'minimal' {
            $outer.Background = Brush $bg
            $sp = New-Object System.Windows.Controls.StackPanel
            $dot = New-Object System.Windows.Controls.Border
            $dot.Width = [int](8 * $scale); $dot.Height = [int](8 * $scale)
            $dot.CornerRadius = [System.Windows.CornerRadius]::new([int](4 * $scale)); $dot.Background = Brush $accent
            $dot.HorizontalAlignment = 'Left'; $dot.Margin = [System.Windows.Thickness]::new(0, 0, 0, [int](6 * $scale))
            $sp.Children.Add($dot) | Out-Null
            $sp.Children.Add((New-TB $message $text $msgSize $false)) | Out-Null
            $outer.Child = $sp
        }
        'outline' {
            $outer.Background = Brush $bg
            $outer.BorderBrush = Brush $accent
            $outer.BorderThickness = [System.Windows.Thickness]::new([math]::Max(2, [int][math]::Round(2 * $scale)))
            $sp = New-Object System.Windows.Controls.StackPanel
            $sp.Children.Add((New-TB 'Vencord Auto-Updater' $accent $titleSize $true)) | Out-Null
            $m = New-TB $message $sub $msgSize $false; $m.Margin = [System.Windows.Thickness]::new(0, [int](5 * $scale), 0, 0)
            $sp.Children.Add($m) | Out-Null
            $outer.Child = $sp
        }
        default {
            # bar
            $outer.Background = Brush $bg
            $grid = New-Object System.Windows.Controls.Grid
            $c0 = New-Object System.Windows.Controls.ColumnDefinition; $c0.Width = [System.Windows.GridLength]::new([math]::Max(5, 6 * $scale))
            $c1 = New-Object System.Windows.Controls.ColumnDefinition; $c1.Width = [System.Windows.GridLength]::new(1, 'Star')
            $grid.ColumnDefinitions.Add($c0); $grid.ColumnDefinitions.Add($c1)
            $bar = New-Object System.Windows.Controls.Border
            $bar.Background = Brush $accent; $bar.CornerRadius = [System.Windows.CornerRadius]::new(3)
            $bar.Margin = [System.Windows.Thickness]::new(0, 0, [int](12 * $scale), 0)
            [System.Windows.Controls.Grid]::SetColumn($bar, 0)
            $sp = New-Object System.Windows.Controls.StackPanel
            [System.Windows.Controls.Grid]::SetColumn($sp, 1)
            $sp.Children.Add((New-TB 'Vencord Auto-Updater' $text $titleSize $true)) | Out-Null
            $m = New-TB $message $sub $msgSize $false; $m.Margin = [System.Windows.Thickness]::new(0, [int](5 * $scale), 0, 0)
            $sp.Children.Add($m) | Out-Null
            $grid.Children.Add($bar) | Out-Null; $grid.Children.Add($sp) | Out-Null
            $outer.Child = $grid
        }
    }
    $outer
}

# $color is accepted for backwards-compatibility but ignored (notifications follow the theme).
function Show-Alert([string]$message, [string]$color = '', [bool]$Force = $false) {
    if (-not $Force -and $script:Config -and -not $script:Config.ui.notificationsEnabled) { return }
    try {
        if ($script:CurrentAlert) { try { $script:CurrentAlert.Close() } catch { } }
        $scale = if ($script:Config) { [double]$script:Config.ui.notifyScale } else { 1 }; if ($scale -le 0) { $scale = 1 }
        $dur   = if ($script:Config) { [double]$script:Config.ui.notifyDurationSec } else { 7 }
        $w = New-Object System.Windows.Window
        $w.WindowStyle = 'None'; $w.AllowsTransparency = $true
        $w.Background = [System.Windows.Media.Brushes]::Transparent
        $w.Topmost = $true; $w.ShowInTaskbar = $false; $w.ShowActivated = $false
        $w.Opacity = 0.94    # a little transparent
        $w.Width = [int][math]::Round(360 * $scale); $w.SizeToContent = 'Height'
        $w.WindowStartupLocation = 'Manual'; $w.Left = 20; $w.Top = 20
        $w.Content = New-AlertVisual $message
        $w.Add_MouseLeftButtonDown({ try { $this.Close() } catch { } })
        $script:CurrentAlert = $w
        $w.Show()
        $t = New-Object System.Windows.Threading.DispatcherTimer
        $t.Interval = [TimeSpan]::FromSeconds($dur)
        $t.Add_Tick({ param($s, $e) $s.Stop(); try { $w.Close() } catch { } }.GetNewClosure())
        $t.Start()
    } catch { Write-Log "Alert error: $($_.Exception.Message)" 'WARN' }
}

# ------------------------------------------------------------------ monitor
function Invoke-Monitor {
    $states = @{}
    $candidates = @()
    foreach ($inst in $script:Config.installs) {
        $st = Get-State $inst
        $states[$inst.path] = $st
        $key = $inst.path
        if ($inst.enabled -and $st.Running -and -not $st.Patched -and $st.Resources) {
            $candidates += $inst
            if (-not $script:Alerted.ContainsKey($key)) {
                $script:Alerted[$key] = $true
                if ($script:Config.monitoringEnabled) {
                    Show-Alert "Detected a $($inst.name) instance without Vencord. Re-injecting Vencord and restarting Discord..." '#F23F43'
                    Write-Log "Detected $($inst.name) without Vencord. Patching..." 'ACTION'
                } else {
                    Show-Alert "Detected a $($inst.name) instance without Vencord. Monitoring is OFF, so leaving it as-is." '#FAA61A'
                    Write-Log "Detected $($inst.name) without Vencord (monitoring OFF)." 'WARN'
                }
            }
        }
        if ($st.Patched -and $script:Alerted.ContainsKey($key)) { $script:Alerted.Remove($key) | Out-Null }
    }
    $script:LastStates = $states

    if ($script:Config.monitoringEnabled -and $candidates.Count -gt 0) {
        if (Get-Process -Name 'Update' -ErrorAction SilentlyContinue) {
            Write-Log 'Discord update in progress; deferring patch.' 'WARN'
        } else {
            $done = @()
            foreach ($c in $candidates) {
                try {
                    Stop-DiscordProcesses $c.branch
                    Invoke-Patch $states[$c.path].Resources $script:Stub
                    Write-Log "$($c.name) patched successfully." 'OK'; $done += $c
                } catch { Write-Log "Failed to patch $($c.name): $($_.Exception.Message)" 'ERROR' }
            }
            foreach ($c in $done) {
                Start-Discord $c.path "$($c.branch).exe"
                Write-Log "Restarted $($c.name)." 'OK'
                Show-Alert "Vencord re-injected into $($c.name). Discord has been restarted." '#23A55A'
            }
            if ($done.Count -gt 0) { foreach ($c in $done) { $script:LastStates[$c.path] = Get-State $c } }
        }
    }
    Update-StatusUi
    Build-InstallRows
}

# ------------------------------------------------------------------ UI build
$MainXaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Vencord Auto-Updater" Width="800" Height="620"
        WindowStartupLocation="CenterScreen" WindowStyle="None"
        AllowsTransparency="True" Background="Transparent" ResizeMode="CanMinimize">
  <Window.Resources>
    <SolidColorBrush x:Key="Bg" Color="#1E1F22"/>
    <SolidColorBrush x:Key="Card" Color="#2B2D31"/>
    <SolidColorBrush x:Key="Card2" Color="#313338"/>
    <SolidColorBrush x:Key="Border" Color="#3A3C42"/>
    <SolidColorBrush x:Key="Accent" Color="#5865F2"/>
    <SolidColorBrush x:Key="AccentHover" Color="#4752C4"/>
    <SolidColorBrush x:Key="OnAccent" Color="#FFFFFF"/>
    <SolidColorBrush x:Key="Text" Color="#F2F3F5"/>
    <SolidColorBrush x:Key="Sub" Color="#B5BAC1"/>
    <SolidColorBrush x:Key="GhostBg" Color="#383A40"/>
    <SolidColorBrush x:Key="GhostHover" Color="#41434A"/>
    <SolidColorBrush x:Key="Scroll" Color="#4E5058"/>
    <Style x:Key="Pill" TargetType="Button">
      <Setter Property="Foreground" Value="{DynamicResource OnAccent}"/>
      <Setter Property="Background" Value="{DynamicResource Accent}"/>
      <Setter Property="FontWeight" Value="SemiBold"/><Setter Property="FontSize" Value="13"/>
      <Setter Property="Height" Value="40"/><Setter Property="Cursor" Value="Hand"/>
      <Setter Property="Template"><Setter.Value>
        <ControlTemplate TargetType="Button">
          <Border CornerRadius="7" Background="{TemplateBinding Background}" Padding="18,0">
            <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/>
          </Border>
        </ControlTemplate></Setter.Value></Setter>
      <Style.Triggers><Trigger Property="IsMouseOver" Value="True"><Setter Property="Background" Value="{DynamicResource AccentHover}"/></Trigger></Style.Triggers>
    </Style>
    <Style x:Key="Ghost" TargetType="Button">
      <Setter Property="Foreground" Value="{DynamicResource Text}"/>
      <Setter Property="Background" Value="{DynamicResource GhostBg}"/>
      <Setter Property="FontWeight" Value="SemiBold"/><Setter Property="FontSize" Value="12"/>
      <Setter Property="Height" Value="36"/><Setter Property="Cursor" Value="Hand"/>
      <Setter Property="Template"><Setter.Value>
        <ControlTemplate TargetType="Button">
          <Border CornerRadius="6" Background="{TemplateBinding Background}" BorderBrush="{DynamicResource Border}" BorderThickness="1" Padding="14,0">
            <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/>
          </Border>
        </ControlTemplate></Setter.Value></Setter>
      <Style.Triggers><Trigger Property="IsMouseOver" Value="True"><Setter Property="Background" Value="{DynamicResource GhostHover}"/></Trigger></Style.Triggers>
    </Style>
    <Style x:Key="WinBtn" TargetType="Button">
      <Setter Property="Foreground" Value="{DynamicResource Sub}"/><Setter Property="Background" Value="Transparent"/>
      <Setter Property="Width" Value="46"/><Setter Property="Height" Value="46"/><Setter Property="FontSize" Value="14"/><Setter Property="Cursor" Value="Hand"/>
      <Setter Property="Template"><Setter.Value>
        <ControlTemplate TargetType="Button">
          <Border x:Name="b" Background="{TemplateBinding Background}"><ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/></Border>
          <ControlTemplate.Triggers><Trigger Property="IsMouseOver" Value="True"><Setter TargetName="b" Property="Background" Value="{DynamicResource GhostBg}"/></Trigger></ControlTemplate.Triggers>
        </ControlTemplate></Setter.Value></Setter>
    </Style>
    <!-- themed scrollbar: thin, rounded thumb, no arrow buttons -->
    <Style x:Key="ScrollThumb" TargetType="{x:Type Thumb}">
      <Setter Property="OverridesDefaultStyle" Value="true"/>
      <Setter Property="IsTabStop" Value="false"/>
      <Setter Property="Background" Value="{DynamicResource Scroll}"/>
      <Setter Property="MinHeight" Value="28"/>
      <Setter Property="Template"><Setter.Value>
        <ControlTemplate TargetType="{x:Type Thumb}">
          <Border CornerRadius="4" Background="{TemplateBinding Background}" Margin="2,0"/>
        </ControlTemplate></Setter.Value></Setter>
      <Style.Triggers>
        <Trigger Property="IsMouseOver" Value="True"><Setter Property="Background" Value="{DynamicResource Accent}"/></Trigger>
        <Trigger Property="IsDragging" Value="True"><Setter Property="Background" Value="{DynamicResource Accent}"/></Trigger>
      </Style.Triggers>
    </Style>
    <Style x:Key="ScrollHidden" TargetType="{x:Type RepeatButton}">
      <Setter Property="OverridesDefaultStyle" Value="true"/>
      <Setter Property="Focusable" Value="false"/><Setter Property="IsTabStop" Value="false"/>
      <Setter Property="Template"><Setter.Value>
        <ControlTemplate TargetType="{x:Type RepeatButton}"><Border Background="Transparent"/></ControlTemplate>
      </Setter.Value></Setter>
    </Style>
    <Style TargetType="{x:Type ScrollBar}">
      <Setter Property="OverridesDefaultStyle" Value="true"/>
      <Setter Property="Width" Value="11"/>
      <Setter Property="Template"><Setter.Value>
        <ControlTemplate TargetType="{x:Type ScrollBar}">
          <Grid Background="Transparent">
            <Track x:Name="PART_Track" IsDirectionReversed="true">
              <Track.DecreaseRepeatButton>
                <RepeatButton Style="{StaticResource ScrollHidden}" Command="{x:Static ScrollBar.PageUpCommand}"/>
              </Track.DecreaseRepeatButton>
              <Track.Thumb>
                <Thumb Style="{StaticResource ScrollThumb}"/>
              </Track.Thumb>
              <Track.IncreaseRepeatButton>
                <RepeatButton Style="{StaticResource ScrollHidden}" Command="{x:Static ScrollBar.PageDownCommand}"/>
              </Track.IncreaseRepeatButton>
            </Track>
          </Grid>
        </ControlTemplate></Setter.Value></Setter>
      <Style.Triggers>
        <Trigger Property="Orientation" Value="Horizontal">
          <Setter Property="Width" Value="Auto"/><Setter Property="Height" Value="11"/>
        </Trigger>
      </Style.Triggers>
    </Style>
  </Window.Resources>
  <Border Margin="12" CornerRadius="8" Background="{DynamicResource Bg}" BorderBrush="{DynamicResource Border}" BorderThickness="1">
    <Border.Effect><DropShadowEffect BlurRadius="28" ShadowDepth="0" Opacity="0.7" Color="#000000"/></Border.Effect>
    <Grid>
      <Grid.RowDefinitions><RowDefinition Height="50"/><RowDefinition Height="*"/></Grid.RowDefinitions>
      <Grid x:Name="TitleBar" Grid.Row="0" Background="Transparent">
        <StackPanel Orientation="Horizontal" VerticalAlignment="Center" Margin="22,0,0,0">
          <Border x:Name="TitleDot" Width="10" Height="10" CornerRadius="2" Background="{DynamicResource Accent}">
            <Border.Effect><DropShadowEffect BlurRadius="12" ShadowDepth="0" Color="#5865F2" Opacity="0.9"/></Border.Effect>
          </Border>
          <TextBlock Text="VENCORD" Foreground="{DynamicResource Text}" FontSize="14" FontWeight="Bold" Margin="12,0,0,0" VerticalAlignment="Center"/>
          <TextBlock Text="AUTO-UPDATER" Foreground="{DynamicResource Accent}" FontSize="14" FontWeight="Bold" Margin="6,0,0,0" VerticalAlignment="Center"/>
        </StackPanel>
        <StackPanel Orientation="Horizontal" HorizontalAlignment="Right">
          <Button x:Name="BtnMin" Style="{StaticResource WinBtn}" Content="&#x2013;"/>
          <Button x:Name="BtnClose" Style="{StaticResource WinBtn}" Content="&#x2715;"/>
        </StackPanel>
        <Border x:Name="TitleUnderline" Height="2" VerticalAlignment="Bottom" Background="{DynamicResource Border}" Margin="0,0,0,0"/>
      </Grid>
      <ScrollViewer x:Name="MainScroll" Grid.Row="1" VerticalScrollBarVisibility="Auto" Margin="20,2,20,18">
        <StackPanel>
          <Border Background="{DynamicResource Card}" BorderBrush="{DynamicResource Border}" BorderThickness="1" CornerRadius="10">
            <Grid>
              <Grid.ColumnDefinitions><ColumnDefinition Width="4"/><ColumnDefinition Width="*"/></Grid.ColumnDefinitions>
              <Border x:Name="AccentStrip" Grid.Column="0" Background="{DynamicResource Accent}" CornerRadius="10,0,0,10"/>
              <Grid Grid.Column="1" Margin="22,18,20,18">
                <StackPanel>
                  <TextBlock Text="MONITORING" Foreground="{DynamicResource Accent}" FontSize="11" FontWeight="Bold"/>
                  <StackPanel Orientation="Horizontal" Margin="0,8,0,0">
                    <Border x:Name="StatusDot" Width="16" Height="16" CornerRadius="8" Background="#23A55A" VerticalAlignment="Center">
                      <Border.Effect><DropShadowEffect x:Name="StatusDotGlow" BlurRadius="14" ShadowDepth="0" Color="#23A55A" Opacity="0.9"/></Border.Effect>
                    </Border>
                    <TextBlock x:Name="StatusText" Text="Active" Foreground="{DynamicResource Text}" FontSize="27" FontWeight="Bold" Margin="12,0,0,0"/>
                  </StackPanel>
                  <TextBlock x:Name="StatusSub" Text="Watching for Discord updates..." Foreground="{DynamicResource Sub}" FontSize="12" Margin="0,7,0,0"/>
                </StackPanel>
                <Button x:Name="BtnToggle" Style="{StaticResource Pill}" Content="Turn Off" HorizontalAlignment="Right" VerticalAlignment="Center" Width="128"/>
              </Grid>
            </Grid>
          </Border>
          <TextBlock Text="MANAGED DISCORD INSTALLS" Foreground="{DynamicResource Accent}" FontSize="11" FontWeight="Bold" Margin="2,22,0,10"/>
          <StackPanel x:Name="InstallList"/>
          <StackPanel Orientation="Horizontal" Margin="0,4,0,0">
            <Button x:Name="BtnDetectDiscord" Style="{StaticResource Ghost}" Content="Detect Discord"/>
            <Button x:Name="BtnDetectPTB" Style="{StaticResource Ghost}" Content="Detect PTB" Margin="10,0,0,0"/>
            <Button x:Name="BtnAddCustom" Style="{StaticResource Ghost}" Content="Add custom path..." Margin="10,0,0,0"/>
          </StackPanel>

          <TextBlock Text="APPEARANCE AND NOTIFICATIONS" Foreground="{DynamicResource Accent}" FontSize="11" FontWeight="Bold" Margin="2,22,0,10"/>
          <Border Background="{DynamicResource Card}" BorderBrush="{DynamicResource Border}" BorderThickness="1" CornerRadius="10" Padding="20">
            <StackPanel>
              <Grid>
                <TextBlock Text="Show notifications" Foreground="{DynamicResource Text}" FontSize="14" FontWeight="SemiBold" VerticalAlignment="Center"/>
                <Button x:Name="BtnNotifyToggle" Width="62" Height="30" HorizontalAlignment="Right" VerticalAlignment="Center" Foreground="White" FontSize="11" FontWeight="SemiBold" Cursor="Hand">
                  <Button.Template><ControlTemplate TargetType="Button"><Border CornerRadius="8" Background="{TemplateBinding Background}"><ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/></Border></ControlTemplate></Button.Template>
                </Button>
              </Grid>
              <TextBlock Text="Theme" Foreground="{DynamicResource Sub}" FontSize="12" Margin="0,18,0,9"/>
              <StackPanel x:Name="ThemePanel" Orientation="Horizontal"/>
              <TextBlock Text="Notification style" Foreground="{DynamicResource Sub}" FontSize="12" Margin="0,18,0,9"/>
              <StackPanel x:Name="StylePanel" Orientation="Horizontal"/>
              <Grid Margin="0,18,0,0">
                <TextBlock Text="Notification size" Foreground="{DynamicResource Sub}" FontSize="12" VerticalAlignment="Center"/>
                <TextBlock x:Name="LblNotifyScale" Foreground="{DynamicResource Text}" FontSize="12" HorizontalAlignment="Right"/>
              </Grid>
              <Slider x:Name="SliderNotifyScale" Minimum="70" Maximum="150" TickFrequency="5" IsSnapToTickEnabled="True" Margin="0,4,0,0"/>
              <Grid Margin="0,12,0,0">
                <TextBlock Text="Notification duration" Foreground="{DynamicResource Sub}" FontSize="12" VerticalAlignment="Center"/>
                <TextBlock x:Name="LblNotifyDur" Foreground="{DynamicResource Text}" FontSize="12" HorizontalAlignment="Right"/>
              </Grid>
              <Slider x:Name="SliderNotifyDur" Minimum="3" Maximum="15" TickFrequency="1" IsSnapToTickEnabled="True" Margin="0,4,0,0"/>
              <Button x:Name="BtnTestNotify" Style="{StaticResource Ghost}" Content="Preview notification" HorizontalAlignment="Left" Margin="0,18,0,0"/>
            </StackPanel>
          </Border>

          <TextBlock Text="ACTIVITY" Foreground="{DynamicResource Accent}" FontSize="11" FontWeight="Bold" Margin="2,22,0,10"/>
          <Border Background="{DynamicResource Card}" BorderBrush="{DynamicResource Border}" BorderThickness="1" CornerRadius="10" Padding="14" Height="130">
            <ScrollViewer x:Name="LogScroll" VerticalScrollBarVisibility="Auto">
              <TextBlock x:Name="LogText" Foreground="{DynamicResource Sub}" FontFamily="Consolas" FontSize="11" TextWrapping="Wrap"/>
            </ScrollViewer>
          </Border>
        </StackPanel>
      </ScrollViewer>
    </Grid>
  </Border>
</Window>
'@

$RowXaml = @'
<Border xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Background="#313338" CornerRadius="8" Padding="16,13" Margin="0,0,0,9">
  <Grid>
    <Grid.ColumnDefinitions><ColumnDefinition Width="*"/><ColumnDefinition Width="Auto"/></Grid.ColumnDefinitions>
    <StackPanel Grid.Column="0">
      <StackPanel Orientation="Horizontal">
        <TextBlock x:Name="RowName" Foreground="#F2F3F5" FontSize="14" FontWeight="SemiBold" VerticalAlignment="Center"/>
        <Border x:Name="RowBadge" CornerRadius="4" Padding="7,2" Margin="9,0,0,0" VerticalAlignment="Center">
          <TextBlock x:Name="RowStatus" Foreground="White" FontSize="10" FontWeight="Bold"/>
        </Border>
      </StackPanel>
      <TextBlock x:Name="RowPath" Foreground="#B5BAC1" FontSize="11" Margin="0,5,0,0" TextTrimming="CharacterEllipsis" MaxWidth="470" HorizontalAlignment="Left"/>
    </StackPanel>
    <StackPanel Grid.Column="1" Orientation="Horizontal" VerticalAlignment="Center">
      <Button x:Name="RowToggle" Width="62" Height="30" Foreground="White" FontSize="11" FontWeight="SemiBold" Cursor="Hand">
        <Button.Template><ControlTemplate TargetType="Button">
          <Border CornerRadius="8" Background="{TemplateBinding Background}"><ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/></Border>
        </ControlTemplate></Button.Template>
      </Button>
      <Button x:Name="RowRemove" Width="30" Height="30" Margin="8,0,0,0" Foreground="#B5BAC1" Content="&#x2715;" FontSize="12" Cursor="Hand">
        <Button.Template><ControlTemplate TargetType="Button">
          <Border x:Name="rb" CornerRadius="8" Background="Transparent"><ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/></Border>
          <ControlTemplate.Triggers><Trigger Property="IsMouseOver" Value="True"><Setter TargetName="rb" Property="Background" Value="#F23F43"/></Trigger></ControlTemplate.Triggers>
        </ControlTemplate></Button.Template>
      </Button>
    </StackPanel>
  </Grid>
</Border>
'@

function Add-LogLine([string]$text) {
    if (-not $script:Win) { return }
    $tb = $script:Win.FindName('LogText')
    $stamp = (Get-Date -Format 'HH:mm:ss')
    $tb.Text = ($tb.Text + "$stamp  $text`n")
    $lines = $tb.Text -split "`n"
    if ($lines.Count -gt 200) { $tb.Text = ($lines | Select-Object -Last 200) -join "`n" }
    $script:Win.FindName('LogScroll').ScrollToBottom()
}

function Update-StatusUi {
    if (-not $script:Win) { return }
    $p = Get-ThemePalette
    $on = $script:Config.monitoringEnabled
    $dotColor = if ($on) { $p.On } else { '#80848E' }
    $sd = $script:Win.FindName('StatusDot'); $sd.Background = Brush $dotColor; $sd.Effect = New-Glow $dotColor 14
    $script:Win.FindName('StatusText').Text = $(if ($on) { 'Active' } else { 'Paused' })
    $script:Win.FindName('StatusSub').Text = $(if ($on) { 'Watching for Discord instances running without Vencord...' } else { 'Monitoring is paused. Discord will not be re-patched.' })
    $bt = $script:Win.FindName('BtnToggle')
    $bt.Content = $(if ($on) { 'Turn Off' } else { 'Turn On' })
    $bt.Background = Brush ($(if ($on) { $p.Accent } else { $p.On }))
    $bt.Foreground = Brush ($(if ($on) { $p.OnAccent } else { $p.OnText }))
    $bt.Effect = New-Glow ($(if ($on) { $p.Accent } else { $p.On })) 16
    if ($script:Ni) {
        $script:Ni.Text = "$AppName - " + $(if ($on) { 'Active' } else { 'Paused' })
        $stateIcon = if ($on) { $script:IconOn } else { $script:IconOff }
        if ($stateIcon) { $script:Ni.Icon = $stateIcon }
    }
}

function Set-PanelSelection($panel, $selectedTag) {
    $p = Get-ThemePalette
    foreach ($ch in $panel.Children) {
        $sel = ($ch.Tag -eq $selectedTag)
        $ch.BorderBrush = Brush ($(if ($sel) { $p.Accent } else { $p.Border }))
        $ch.BorderThickness = [System.Windows.Thickness]::new($(if ($sel) { 2 } else { 1 }))
        $ch.Background = Brush ($(if ($sel) { $p.GhostHover } else { $p.Ghost }))
        $ch.Effect = if ($sel) { New-Glow $p.Accent 10 } else { $null }
    }
}

function Update-SettingsUi {
    if (-not $script:Win) { return }
    $p = Get-ThemePalette
    $n = $script:Config.ui.notificationsEnabled
    $bn = $script:Win.FindName('BtnNotifyToggle')
    $bn.Content = $(if ($n) { 'On' } else { 'Off' }); $bn.Background = Brush ($(if ($n) { $p.On } else { $p.GhostHover })); $bn.Foreground = Brush ($(if ($n) { $p.OnText } else { $p.Text }))
    $script:Win.FindName('LblNotifyScale').Text = "$([int]([double]$script:Config.ui.notifyScale * 100)) %"
    $script:Win.FindName('LblNotifyDur').Text = "$([int]$script:Config.ui.notifyDurationSec) s"
    Set-PanelSelection $script:Win.FindName('ThemePanel') $script:Config.ui.theme
    Set-PanelSelection $script:Win.FindName('StylePanel') $script:Config.ui.notifyStyle
    # re-tint label text inside the selector chips to match the theme
    foreach ($panel in @($script:Win.FindName('ThemePanel'), $script:Win.FindName('StylePanel'))) {
        foreach ($ch in $panel.Children) { if ($ch.Child) { $ch.Child.Foreground = Brush $p.Text } }
    }
}

function Build-InstallRows {
    if (-not $script:Win) { return }
    $p = Get-ThemePalette
    $list = $script:Win.FindName('InstallList')
    $list.Children.Clear()
    if (-not $script:Config.installs -or @($script:Config.installs).Count -eq 0) {
        $empty = New-Object System.Windows.Controls.TextBlock
        $empty.Text = 'No Discord installs added yet. Use the buttons below to detect or add one.'
        $empty.Foreground = Brush $p.Sub; $empty.FontSize = 12; $empty.Margin = '2,0,0,8'
        $list.Children.Add($empty) | Out-Null
        return
    }
    foreach ($inst in $script:Config.installs) {
        $st = $script:LastStates[$inst.path]; if (-not $st) { $st = Get-State $inst }
        $row = ConvertFrom-Xaml $RowXaml
        $row.Background = Brush $p.RowBg
        $row.BorderBrush = Brush $p.Border; $row.BorderThickness = [System.Windows.Thickness]::new(1)
        $row.FindName('RowName').Text = $inst.name; $row.FindName('RowName').Foreground = Brush $p.Text
        $row.FindName('RowPath').Text = $inst.path; $row.FindName('RowPath').Foreground = Brush $p.Sub
        # status badge
        if (-not $st.Installed) { $bc = '#80848E'; $bf = '#FFFFFF'; $bt = 'Not installed' }
        elseif ($st.Patched)    { $bc = $p.On;     $bf = $p.OnText; $bt = 'Vencord active' }
        elseif ($st.Running)    { $bc = '#F23F43'; $bf = '#FFFFFF'; $bt = 'No Vencord' }
        else                    { $bc = '#80848E'; $bf = '#FFFFFF'; $bt = 'Not patched' }
        $row.FindName('RowBadge').Background = Brush $bc
        $row.FindName('RowStatus').Text = $bt; $row.FindName('RowStatus').Foreground = Brush $bf
        # toggle
        $tg = $row.FindName('RowToggle')
        $tg.Background = Brush ($(if ($inst.enabled) { $p.On } else { $p.GhostHover }))
        $tg.Foreground = Brush ($(if ($inst.enabled) { $p.OnText } else { $p.Text }))
        $tg.Content = $(if ($inst.enabled) { 'On' } else { 'Off' })
        $tg.Tag = $inst
        $tg.Add_Click({ $i = $this.Tag; $i.enabled = -not $i.enabled; Save-Config; Invoke-Monitor })
        # remove (custom only)
        $rm = $row.FindName('RowRemove')
        $rm.Foreground = Brush $p.Sub
        if ($inst.custom) {
            $rm.Tag = $inst
            $rm.Add_Click({ $i = $this.Tag; $script:Config.installs = @($script:Config.installs | Where-Object { $_.path -ne $i.path }); Save-Config; Add-LogLine "Removed $($i.name)"; Update-StatusUi; Build-InstallRows })
        } else { $rm.Visibility = 'Collapsed' }
        $list.Children.Add($row) | Out-Null
    }
}

# ------------------------------------------------------------------ tray
function Get-AppIcon {
    # Prefer the bundled logo; otherwise use the icon embedded in our own exe.
    $ico = Join-Path $ScriptDir 'app.ico'
    if (Test-Path $ico) { try { return New-Object System.Drawing.Icon($ico) } catch { } }
    try {
        $self = [System.Diagnostics.Process]::GetCurrentProcess().MainModule.FileName
        if ($self -match 'VencordAutoUpdater\.exe$') { return [System.Drawing.Icon]::ExtractAssociatedIcon($self) }
    } catch { }
    [System.Drawing.SystemIcons]::Application
}

function Show-MainWindow {
    $script:Win.Show(); $script:Win.WindowState = 'Normal'; $script:Win.Activate(); $script:Win.Topmost = $true; $script:Win.Topmost = $false
}

function Quit-App {
    try { if ($script:Timer) { $script:Timer.Stop() } } catch { }
    try { if ($script:Ni) { $script:Ni.Visible = $false; $script:Ni.Dispose() } } catch { }
    try { $script:App.Shutdown() } catch { }
}

# ------------------------------------------------------------------ main
function Start-App {
    Load-Config
    $script:Stub = Get-StubAsarBytes -Patcher $PatcherPath
    if (-not (Test-Path $PatcherPath)) { Write-Log "patcher.js not found at $PatcherPath (run the Vencord installer once)." 'WARN' }

    $script:App = New-Object System.Windows.Application
    $script:App.ShutdownMode = [System.Windows.ShutdownMode]::OnExplicitShutdown
    # Never hard-crash on a UI handler error: log it and keep running.
    $script:App.Add_DispatcherUnhandledException({
        param($s, $e)
        Write-Log "UI exception: $($e.Exception.Message)`n$($e.Exception.StackTrace)" 'ERROR'
        try { Add-LogLine "Handled error: $($e.Exception.Message)" } catch { }
        $e.Handled = $true
    })
    $script:Win = ConvertFrom-Xaml $MainXaml

    # always open scrolled to the top
    $script:Win.Add_ContentRendered({ try { $ms = $script:Win.FindName('MainScroll'); if ($ms) { $ms.ScrollToTop() } } catch { } })

    # title bar
    $script:Win.FindName('TitleBar').Add_MouseLeftButtonDown({ try { $script:Win.DragMove() } catch { } })
    $script:Win.FindName('BtnMin').Add_Click({ $script:Win.Hide(); if ($script:Ni) { $script:Ni.ShowBalloonTip(2000, $AppName, 'Minimized to the notification area. Click the "show hidden icons" arrow to find it.', 'Info') } })
    $script:Win.FindName('BtnClose').Add_Click({ $script:Win.Hide(); if ($script:Ni) { $script:Ni.ShowBalloonTip(2500, $AppName, 'Still running in the background. Right-click the tray icon to quit.', 'Info') } })

    # status toggle
    $script:Win.FindName('BtnToggle').Add_Click({
        $script:Config.monitoringEnabled = -not $script:Config.monitoringEnabled
        Save-Config; Add-LogLine ("Monitoring turned " + $(if ($script:Config.monitoringEnabled) { 'ON' } else { 'OFF' }))
        $script:Alerted.Clear(); Invoke-Monitor
    })

    # detect / add
    $script:Win.FindName('BtnDetectDiscord').Add_Click({
        $root = Join-Path $env:LOCALAPPDATA 'Discord'
        if (Test-Path (Join-Path $root 'Update.exe')) { [void](Ensure-Install 'Discord' 'Discord' $root $true $false); Save-Config; Add-LogLine 'Detected Discord (stable) and enabled it.'; Invoke-Monitor }
        else { Add-LogLine 'Discord (stable) not found in LOCALAPPDATA.'; Show-Alert 'Discord (stable) was not found.' '#FAA61A' }
    })
    $script:Win.FindName('BtnDetectPTB').Add_Click({
        $root = Join-Path $env:LOCALAPPDATA 'DiscordPTB'
        if (Test-Path (Join-Path $root 'Update.exe')) { [void](Ensure-Install 'DiscordPTB' 'DiscordPTB' $root $true $false); Save-Config; Add-LogLine 'Detected Discord PTB and enabled it.'; Invoke-Monitor }
        else { Add-LogLine 'Discord PTB not found in LOCALAPPDATA.'; Show-Alert 'Discord PTB was not found.' '#FAA61A' }
    })
    $script:Win.FindName('BtnAddCustom').Add_Click({
        $dlg = New-Object System.Windows.Forms.FolderBrowserDialog
        $dlg.Description = 'Select a Discord install folder (the one containing Update.exe / app-* folders)'
        if ($dlg.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {
            $p = $dlg.SelectedPath
            $valid = (Test-Path (Join-Path $p 'Update.exe')) -or @(Get-ChildItem -Path $p -Directory -Filter 'app-*' -ErrorAction SilentlyContinue).Count -gt 0
            if (-not $valid) { Add-LogLine "Not a Discord install: $p"; Show-Alert 'That folder does not look like a Discord install.' '#FAA61A'; return }
            $branch = Get-BranchFromLeaf $p
            [void](Ensure-Install ("Custom: " + (Split-Path -Leaf $p)) $branch $p $true $true)
            Save-Config; Add-LogLine "Added custom path: $p"; Invoke-Monitor
        }
    })

    # ---- settings: notifications ----
    $script:Win.FindName('BtnNotifyToggle').Add_Click({
        $script:Config.ui.notificationsEnabled = -not $script:Config.ui.notificationsEnabled; Save-Config
        Add-LogLine ("Notifications " + $(if ($script:Config.ui.notificationsEnabled) { 'ON' } else { 'OFF' }))
        Update-SettingsUi
    })
    $script:Win.FindName('BtnTestNotify').Add_Click({ Show-Alert 'Preview notification. Detected a Discord instance without Vencord.' '' $true })

    # ---- settings: theme selector (Discord / Dark / Light / High Contrast) ----
    $themePanel = $script:Win.FindName('ThemePanel')
    foreach ($key in $Themes.Keys) {
        $tb = New-Object System.Windows.Controls.Border
        $tb.CornerRadius = [System.Windows.CornerRadius]::new(6); $tb.Padding = '15,8'; $tb.Margin = '0,0,8,0'; $tb.Cursor = 'Hand'; $tb.Tag = $key
        $lbl = New-Object System.Windows.Controls.TextBlock
        $lbl.Text = $Themes[$key].Label; $lbl.FontSize = 12; $lbl.FontWeight = 'SemiBold'
        $tb.Child = $lbl
        $tb.Add_MouseLeftButtonUp({ $k = $this.Tag; $script:Config.ui.theme = $k; Save-Config; Apply-Theme; Add-LogLine "Theme: $($Themes[$k].Label)" })
        $themePanel.Children.Add($tb) | Out-Null
    }

    # ---- settings: notification style selector ----
    $stylePanel = $script:Win.FindName('StylePanel')
    foreach ($styleName in $NotifyStyles) {
        $sb = New-Object System.Windows.Controls.Border
        $sb.CornerRadius = [System.Windows.CornerRadius]::new(6); $sb.Padding = '15,8'; $sb.Margin = '0,0,8,0'; $sb.Cursor = 'Hand'; $sb.Tag = $styleName
        $lbl = New-Object System.Windows.Controls.TextBlock
        $lbl.Text = (Get-Culture).TextInfo.ToTitleCase($styleName); $lbl.FontSize = 12; $lbl.FontWeight = 'SemiBold'
        $sb.Child = $lbl
        $sb.Add_MouseLeftButtonUp({ $s = $this.Tag; $script:Config.ui.notifyStyle = $s; Save-Config; Update-SettingsUi; Add-LogLine "Notification style: $s"; Show-Alert "Style preview: $s. Detected a Discord instance without Vencord." '' $true })
        $stylePanel.Children.Add($sb) | Out-Null
    }

    # ---- settings: sliders ----
    $sScale = $script:Win.FindName('SliderNotifyScale')
    $sScale.Value = [double]$script:Config.ui.notifyScale * 100
    $sScale.Add_ValueChanged({ param($s, $e) $script:Config.ui.notifyScale = [math]::Round($s.Value / 100, 2); $script:Win.FindName('LblNotifyScale').Text = "$([int]$s.Value) %"; Save-Config })
    # live-preview the size when the user releases the slider thumb (so the change is obvious)
    $sScale.AddHandler([System.Windows.Controls.Primitives.Thumb]::DragCompletedEvent, [System.Windows.Controls.Primitives.DragCompletedEventHandler] { Show-Alert 'Size preview. Detected a Discord instance without Vencord.' '' $true })
    $sDur = $script:Win.FindName('SliderNotifyDur')
    $sDur.Value = [double]$script:Config.ui.notifyDurationSec
    $sDur.Add_ValueChanged({ param($s, $e) $script:Config.ui.notifyDurationSec = [int]$s.Value; $script:Win.FindName('LblNotifyDur').Text = "$([int]$s.Value) s"; Save-Config })

    Apply-Theme

    # window icon = the plain logo; tray icon = state logo (green on / red off)
    $appIcon = Get-AppIcon
    try { $script:Win.Icon = [System.Windows.Interop.Imaging]::CreateBitmapSourceFromHIcon($appIcon.Handle, [System.Windows.Int32Rect]::Empty, [System.Windows.Media.Imaging.BitmapSizeOptions]::FromEmptyOptions()) } catch { }
    $script:IconOn  = ConvertTo-IconFromB64 $IconOnB64
    $script:IconOff = ConvertTo-IconFromB64 $IconOffB64
    $script:Ni = New-Object System.Windows.Forms.NotifyIcon
    $trayIcon = if ($script:Config.monitoringEnabled) { $script:IconOn } else { $script:IconOff }
    if (-not $trayIcon) { $trayIcon = $appIcon }
    $script:Ni.Icon = $trayIcon; $script:Ni.Visible = $true; $script:Ni.Text = $AppName
    $menu = New-Object System.Windows.Forms.ContextMenuStrip
    $miOpen = $menu.Items.Add('Open'); $miOpen.Add_Click({ Show-MainWindow })
    $miTog  = $menu.Items.Add('Toggle monitoring'); $miTog.Add_Click({ $script:Win.FindName('BtnToggle').RaiseEvent((New-Object System.Windows.RoutedEventArgs([System.Windows.Controls.Button]::ClickEvent))) })
    [void]$menu.Items.Add('-')
    $miQuit = $menu.Items.Add('Quit'); $miQuit.Add_Click({ Quit-App })
    $script:Ni.ContextMenuStrip = $menu
    $script:Ni.Add_MouseDoubleClick({ Show-MainWindow })

    # initial render
    Update-StatusUi; Update-SettingsUi; Build-InstallRows
    Add-LogLine "$AppName started."
    Write-Log "App started (Tray=$Tray)." 'INFO'

    # monitor timer
    $script:Timer = New-Object System.Windows.Threading.DispatcherTimer
    $iv = [int]$script:Config.intervalSeconds; if ($iv -lt 5) { $iv = 5 }
    $script:Timer.Interval = [TimeSpan]::FromSeconds($iv)
    $script:Timer.Add_Tick({ try { Invoke-Monitor } catch { Write-Log "Monitor error: $($_.Exception.Message)" 'ERROR' } })
    $script:Timer.Start()
    # run one pass shortly after launch
    $script:Win.Dispatcher.InvokeAsync({ try { Invoke-Monitor } catch { Write-Log "Initial monitor error: $($_.Exception.Message)" 'ERROR' } }) | Out-Null

    if ($SelfTest) { Write-Log 'Self-test OK.' 'INFO'; try { $script:Ni.Visible = $false; $script:Ni.Dispose() } catch { }; return }

    if (-not $Tray) { $script:Win.Show() }
    $script:App.Run() | Out-Null
}

# single instance
$script:Mutex = New-Object System.Threading.Mutex($false, 'Global\VencordAutoUpdaterApp')
if (-not $script:Mutex.WaitOne(0)) { Write-Log 'App already running. Exiting.' 'WARN'; return }
try { Start-App }
catch { Write-Log "FATAL: $($_.Exception.Message)`n$($_.ScriptStackTrace)" 'ERROR' }
finally { try { $script:Mutex.ReleaseMutex() } catch { } }
